class Solution {
    private int m;
    private int n;
    private int total;
    private Map<Integer, Integer> map;
    private Random rand;

    public Solution(int m, int n) {
        this.m = m;
        this.n = n;
        this.total = m * n;
        this.map = new HashMap<>();
        this.rand = new Random();
    }

    public int[] flip() {
        int x = rand.nextInt(total);
        int val = map.getOrDefault(x, x);
        int last = total - 1;
        map.put(x, last);
        total--;
        return new int[]{val / n, val % n};
    }

    public void reset() {
        map.clear();
        total = m * n;
    }
}

